('dry_riverbed', 'Сухое русло реки', 'wasteland', 'Кости левиафана виднеются на горизонте. Вода исчезла десятилетия назад.', 3, 5, 2, 0, 0, 0, 0, 1),
('supermarket_ruins', 'Руины Супермаркета', 'city', 'Обваленная крыша. Внутри темно, но могут быть припасы.', 5, 15, 4, 0, 1, 3, 0, 1),
('raider_camp', 'Лагерь Рейдеров', 'ruins', 'Костры еще теплые. Вокруг висят чучела. Пахнет паленым мясом.', 6, 10, 3, 0, 0, 0, 0, 1),
