('pipe_rupture', 'Разлом Трубы', 'radzone', 'Из земли сочится зелёная жижа. Воздух тяжёлый.', 7, 60, 5, 0, 0, 0, 0, 1),
('wind_canyon', 'Ущелье Ветров', 'mountain', 'Сквозняк свистит между скал. Эхо разносит крики.', 2, 0, 1, 0, 0, 0, 0, 1),
